SELECT  FROM post p LEFT JOIN circle c ON c.id=p.circle_id
WHERE p.user_id=#{userId} AND p.region=#{region} AND p.is_deleted=FALSE
ORDER BY p.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT  FROM post p LEFT JOIN circle c ON c.id=p.circle_id
WHERE p.region=#{region} AND p.audit_status=1 AND p.status=1 AND p.is_deleted=FALSE
ORDER BY p.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT  FROM post p LEFT JOIN circle c ON c.id=p.circle_id
WHERE p.circle_id=#{circleId} AND p.region=#{region} AND p.audit_status=1 AND p.status=1 AND p.is_deleted=FALSE
ORDER BY p.id DESC LIMIT #{limit} OFFSET #{offset}
